def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio < 0.3:
            score += 2 / (0.3 - ratio + 1e-10)
            for k in range(1, 5):
                score += ((-1) ** (k + 1)) * (ratio ** (k * 1.5)) / (k ** 2)
        elif 0.3 <= ratio <= 0.7:
            score += 15 * (0.7 - ratio)
            for k in range(1, 3):
                score += np.tanh(ratio * k) * (-1) ** k * 2
            if item % 2 == 0:
                score += 3
            else:
                score -= 1.5
        elif 0.7 < ratio <= 1:
            score += max(0, 8 * (1 - ratio)) - 5 * (ratio - 0.8)**2
            for j in range(1, 6):
                try:
                    score += ((-1) ** j) * np.log1p(ratio * j) / j
                except Exception:
                    score += 0
            if (capacity % 5 == 0) and (item < capacity):
                score += 4
        else:
            score -= 30 * (ratio - 1) ** 2
            for n in range(1, 4):
                score -= (ratio ** n) / (n * 2)
            if item > capacity * 1.5:
                score -= 100
        if 0.4 < ratio < 0.6:
            for m in range(2):
                score += np.sin(m + ratio * np.pi * 2) * (item / (capacity + 1e-9))
        priorities[i] = score
    max_priority = np.max(priorities[np.isfinite(priorities)])
    if max_priority > 1e-12:
        priorities = priorities / max_priority
    return priorities
